1	package zoho
2	
3	import (
4		"bytes"
5		"context"
6		"encoding/json"
7		"fmt"
8		"io"
9		"net/http"
10		"net/url"
11		"strconv"
12		"strings"
13	
14		"golang.org/x/oauth2"
15	)
16	
17	const (
18		apiBase     = "https://mail.zoho.eu/api"
19		inboxFolder = "INBOX"
20	)
21	
22	// Client provides access to the Zoho Mail REST API.
23	type Client struct {
24		http      *http.Client
25		email     string
26		accountID string // cached after first discovery
27	}
28	
29	// NewClient creates a Zoho Mail API client using the provided token source.
30	// email is the configured mailbox address (used to identify the account).
31	func NewClient(ctx context.Context, ts oauth2.TokenSource, email string) *Client {
32		return &Client{
33			http:  oauth2.NewClient(ctx, ts),
34			email: email,
35		}
36	}
37	
38	// apiResponse is the envelope returned by the Zoho Mail API.
39	type apiResponse struct {
40		Status struct {
41			Code        int    `json:"code"`
42			Description string `json:"description"`
43		} `json:"status"`
44		Data json.RawMessage `json:"data"`
45	}
46	
47	func (c *Client) do(req *http.Request) (*apiResponse, error) {
48		resp, err := c.http.Do(req)
49		if err != nil {
50			return nil, fmt.Errorf("http request: %w", err)
51		}
52		defer resp.Body.Close()
53	
54		body, err := io.ReadAll(resp.Body)
55		if err != nil {
56			return nil, fmt.Errorf("reading response body: %w", err)
57		}
58	
59		if resp.StatusCode == http.StatusNoContent {
60			return &apiResponse{}, nil
61		}
62	
63		var ar apiResponse
64		if err := json.Unmarshal(body, &ar); err != nil {
65			return nil, fmt.Errorf("parsing response (status %d): %w", resp.StatusCode, err)
66		}
67	
68		if ar.Status.Code != 200 {
69			return nil, fmt.Errorf("zoho api error %d: %s", ar.Status.Code, ar.Status.Description)
70		}
71	
72		return &ar, nil
73	}
74	
75	func (c *Client) get(ctx context.Context, path string, params url.Values) (*apiResponse, error) {
76		u := apiBase + path
77		if len(params) > 0 {
78			u += "?" + params.Encode()
79		}
80	
81		req, err := http.NewRequestWithContext(ctx, http.MethodGet, u, nil)
82		if err != nil {
83			return nil, fmt.Errorf("building request: %w", err)
84		}
85	
86		return c.do(req)
87	}
88	
89	func (c *Client) post(ctx context.Context, path string, body any) (*apiResponse, error) {
90		data, err := json.Marshal(body)
91		if err != nil {
92			return nil, fmt.Errorf("marshalling request: %w", err)
93		}
94	
95		req, err := http.NewRequestWithContext(ctx, http.MethodPost, apiBase+path, bytes.NewReader(data))
96		if err != nil {
97			return nil, fmt.Errorf("building request: %w", err)
98		}
99		req.Header.Set("Content-Type", "application/json")
100	
101		return c.do(req)
102	}
103	
104	func (c *Client) put(ctx context.Context, path string, body any) (*apiResponse, error) {
105		data, err := json.Marshal(body)
106		if err != nil {
107			return nil, fmt.Errorf("marshalling request: %w", err)
108		}
109	
110		req, err := http.NewRequestWithContext(ctx, http.MethodPut, apiBase+path, bytes.NewReader(data))
111		if err != nil {
112			return nil, fmt.Errorf("building request: %w", err)
113		}
114		req.Header.Set("Content-Type", "application/json")
115	
116		return c.do(req)
117	}
118	
119	func (c *Client) delete(ctx context.Context, path string, params url.Values) (*apiResponse, error) {
120		u := apiBase + path
121		if len(params) > 0 {
122			u += "?" + params.Encode()
123		}
124	
125		req, err := http.NewRequestWithContext(ctx, http.MethodDelete, u, nil)
126		if err != nil {
127			return nil, fmt.Errorf("building request: %w", err)
128		}
129	
130		return c.do(req)
131	}
132	
133	// accountEntry is the shape returned by GET /accounts.
134	type accountEntry struct {
135		AccountID    string `json:"accountId"`
136		EmailAddress string `json:"emailAddress"`
137	}
138	
139	// AccountID returns the Zoho account ID for the configured email address,
140	// fetching it from the API on first call and caching it thereafter.
141	func (c *Client) AccountID(ctx context.Context) (string, error) {
142		if c.accountID != "" {
143			return c.accountID, nil
144		}
145	
146		ar, err := c.get(ctx, "/accounts", nil)
147		if err != nil {
148			return "", fmt.Errorf("listing accounts: %w", err)
149		}
150	
151		var accounts []accountEntry
152		if err := json.Unmarshal(ar.Data, &accounts); err != nil {
153			return "", fmt.Errorf("parsing accounts: %w", err)
154		}
155	
156		for _, a := range accounts {
157			if strings.EqualFold(a.EmailAddress, c.email) {
158				c.accountID = a.AccountID
159				return c.accountID, nil
160			}
161		}
162	
163		return "", fmt.Errorf("no account found for email %q; check 'zoho-mail config show'", c.email)
164	}
165	
166	// Message is a summary of a Zoho mail message.
167	type Message struct {
168		MessageID   string `json:"messageId"`
169		Subject     string `json:"subject"`
170		FromAddress string `json:"fromAddress"`
171		ToAddress   string `json:"toAddress"`
172		ReceivedTime string `json:"receivedTime"`
173		FolderID    string `json:"folderId"`
174		IsRead      bool   `json:"isRead"`
175		Summary     string `json:"summary"`
176	}
177	
178	// MessageDetail is a full message with content.
179	type MessageDetail struct {
180		Message
181		Content     string `json:"content"`
182		HTMLContent string `json:"htmlContent"`
183	}
184	
185	// SendRequest contains the fields needed to send or reply to a message.
186	type SendRequest struct {
187		FromAddress string `json:"fromAddress"`
188		ToAddress   string `json:"toAddress"`
189		CCAddress   string `json:"ccAddress,omitempty"`
190		Subject     string `json:"subject"`
191		Content     string `json:"content"`
192		MailFormat  string `json:"mailFormat"` // "html" or "plaintext"
193		InReplyTo   string `json:"inReplyTo,omitempty"`
194	}
195	
196	// Folder represents a Zoho Mail folder.
197	type Folder struct {
198		FolderID     string `json:"folderId"`
199		FolderName   string `json:"folderName"`
200		FolderType   string `json:"folderType"`
201		MessageCount int    `json:"messageCount"`
202		UnreadCount  int    `json:"unreadCount"`
203	}
204	
205	// ListMessages returns messages in the given folder (pass empty string for INBOX).
206	func (c *Client) ListMessages(ctx context.Context, folderID string, limit, start int) ([]Message, error) {
207		accountID, err := c.AccountID(ctx)
208		if err != nil {
209			return nil, err
210		}
211	
212		params := url.Values{
213			"limit": {strconv.Itoa(limit)},
214			"start": {strconv.Itoa(start)},
215		}
216		if folderID != "" {
217			params.Set("folderId", folderID)
